update creative_chat_session
last_message = #{lastMessage}, last_message_time = #{lastMessageTime}, buyer_unread = #{buyerUnread}, creator_unread = #{creatorUnread}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
where session_id = #{sessionId}
